changeSet.sql:
DO $$
BEGIN
    IF NOT EXISTS (
        SELECT 1 FROM information_schema.columns
        WHERE table_name = 'attachment' AND column_name = 'storage_provider'
    ) THEN
        ALTER TABLE attachment ADD COLUMN storage_provider VARCHAR(20) NOT NULL DEFAULT 'LOCAL';
    END IF;

    IF NOT EXISTS (
        SELECT 1 FROM information_schema.columns
        WHERE table_name = 'attachment' AND column_name = 'visibility'
    ) THEN
        ALTER TABLE attachment ADD COLUMN visibility VARCHAR(20) NOT NULL DEFAULT 'PRIVATE';
    END IF;

    IF NOT EXISTS (
        SELECT 1 FROM information_schema.columns
        WHERE table_name = 'attachment' AND column_name = 'category'
    ) THEN
        ALTER TABLE attachment ADD COLUMN category VARCHAR(50) NOT NULL DEFAULT 'OTHER';
    END IF;
END $$;
